import base64, hmac, hashlib, json

def b64url_decode(s):
    s = s.encode() if isinstance(s, str) else s
    s += b'=' * ((4 - len(s) % 4) % 4)
    return base64.urlsafe_b64decode(s)

def b64url_encode(b):
    return base64.urlsafe_b64encode(b).rstrip(b'=')

def jwt_parts(token):
    header_b64, payload_b64, sig_b64 = token.split('.')
    return header_b64, payload_b64, sig_b64

def jwt_hs256_signing_input(token):
    header_b64, payload_b64, _ = jwt_parts(token)
    return f"{header_b64}.{payload_b64}".encode()

def jwt_sig_b64(token):
    return token.split('.')[-1]

def calc_sig(secret, signing_input):
    return base64.urlsafe_b64encode(hmac.new(secret.encode(), signing_input, hashlib.sha256).digest()).rstrip(b'=')

